import{_ as o,o as s,c as t,ag as r}from"./chunks/framework.BPmc_f4o.js";const h=JSON.parse('{"title":"brut build-assets css","description":"","frontmatter":{},"headers":[],"relativePath":"brut-cli-commands/commands/css.md","filePath":"brut-cli-commands/commands/css.md"}'),a={name:"brut-cli-commands/commands/css.md"};function l(d,e,i,n,c,u){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="brut-build-assets-css" tabindex="-1"><code>brut build-assets css</code> <a class="header-anchor" href="#brut-build-assets-css" aria-label="Permalink to &quot;`brut build-assets css`&quot;">​</a></h1><p>Builds a single CSS file suitable for sending to the browser</p><h2 id="usage" tabindex="-1">USAGE <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;USAGE&quot;">​</a></h2><pre><code>brut build-assets css [options]\n</code></pre><h2 id="description" tabindex="-1">DESCRIPTION <a class="header-anchor" href="#description" aria-label="Permalink to &quot;DESCRIPTION&quot;">​</a></h2><p>This produces a hashed file in every environment, in order to keep environments consistent and reduce differences. If your CSS file references images, fonts, or other assets via <code>url()</code> or other CSS functions, those files will be hashed and copied into the output directory where CSS is served.</p><p>To ensure this happens correctly, your <code>url()</code> or other function must reference the file as a relative file from where your actual source CSS file is located. For example, a font named <code>some-font.ttf</code> would be in <code>app/src/front_end/fonts</code>. To reference this from <code>app/src/front_end/css/index.css</code> you&#39;d use <code>url(&quot;../fonts/some-font.ttf&quot;)</code></p><h2 id="options" tabindex="-1">OPTIONS <a class="header-anchor" href="#options" aria-label="Permalink to &quot;OPTIONS&quot;">​</a></h2><ul><li><code>--env=ENVIRONMENT</code> - Project environment, e.g. test, development, production. Default depends on the command</li><li><code>--log-level=LOG_LEVEL</code> - Log level, which should be debug, info, warn, error, or fatal. Defaults to error</li><li><code>--debug, --verbose</code> - Set log level to debug, and show log messages on stdout</li><li><code>--quiet</code> - Set log level to error</li><li><code>--log-file=FILE</code> - Path to a file where log messages are written. Defaults to $XDG_CACHE_HOME/brut/logs/brut.log</li><li><code>--[no-]log-stdout</code> - Log messages to stdout in addition to the log file</li><li><code>--help, -h</code> - Show help</li><li><code>--[no-]clean</code> - If set, any old files from previous runs are deleted. Defaults to false in production, true everywhere else.</li></ul>',9)])])}const m=o(a,[["render",l]]);export{h as __pageData,m as default};
